plan.dockerfile_template:
FROM {{ .BuildImage }} AS builder
WORKDIR /app
COPY package.json ./
COPY package-lock.json* pnpm-lock.yaml* yarn.lock* ./
RUN {{ .InstallCmd }}
COPY . .
RUN {{ .BuildCmd }}

FROM {{ .RunImage }}
COPY --from=builder /app/dist /usr/share/nginx/html
COPY default.conf /etc/nginx/conf.d/default.conf
EXPOSE {{ .ServicePort }}
